# --- Security: TLS Certificate Management ---

class TLSCertificateManager:
    """Manages TLS certificates for secure gRPC communication."""

    def __init__(self, cert_dir: Optional[str] = None):
        self.cert_dir = cert_dir or os.environ.get(
            'GRPC_CERT_DIR',
            os.path.join(os.path.expanduser('~'), '.grpc_certs')
        )
        os.makedirs(self.cert_dir, mode=0o700, exist_ok=True)

        self.ca_cert_path = os.path.join(self.cert_dir, 'ca.crt')
        self.server_cert_path = os.path.join(self.cert_dir, 'server.crt')
        self.server_key_path = os.path.join(self.cert_dir, 'server.key')

    def certificates_exist(self) -> bool:
        return all(os.path.exists(p) for p in [
            self.ca_cert_path, self.server_cert_path, self.server_key_path
        ])

    def generate_self_signed_certs(self):
        """Generate self-signed certificates for development/testing."""
        try:
            from cryptography import x509
            from cryptography.x509.oid import NameOID
            from cryptography.hazmat.primitives import hashes, serialization
            from cryptography.hazmat.primitives.asymmetric import rsa
            import datetime

            # Generate CA key and certificate
            ca_key = rsa.generate_private_key(
                public_exponent=65537,
                key_size=4096,
            )

            ca_name = x509.Name([
                x509.NameAttribute(NameOID.COMMON_NAME, 'DataProcessor CA'),
                x509.NameAttribute(NameOID.ORGANIZATION_NAME, 'DataProcessor'),
            ])

            ca_cert = (
                x509.CertificateBuilder()
                .subject_name(ca_name)
                .issuer_name(ca_name)
                .public_key(ca_key.public_key())
                .serial_number(x509.random_serial_number())
                .not_valid_before(datetime.datetime.utcnow())
                .not_valid_after(datetime.datetime.utcnow() + datetime.timedelta(days=365))
                .add_extension(
                    x509.BasicConstraints(ca=True, path_length=0),
                    critical=True,
                )
                .sign(ca_key, hashes.SHA256())
            )

            # Generate server key and certificate
            server_key = rsa.generate_private_key(
                public_exponent=65537,
                key_size=4096,
            )

            server_name = x509.Name([
                x509.NameAttribute(NameOID.COMMON_NAME, 'localhost'),
                x509.NameAttribute(NameOID.ORGANIZATION_NAME, 'DataProcessor'),
            ])

            server_cert = (
                x509.CertificateBuilder()
                .subject_name(server_name)
                .issuer_name(ca_name)
                .public_key(server_key.public_key())
                .serial_number(x509.random_serial_number())
                .not_valid_before(datetime.datetime.utcnow())
                .not_valid_after(datetime.datetime.utcnow() + datetime.timedelta(days=365))
                .add_extension(
                    x509.SubjectAlternativeName([
                        x509.DNSName('localhost'),
                        x509.DNSName('*.local'),
                        x509.IPAddress(
                            __import__('ipaddress').IPv4Address('127.0.0.1')
                        ),
                    ]),
                    critical=False,
                )
                .sign(ca_key, hashes.SHA256())
            )

            # Write certificates with restrictive permissions
            with open(self.ca_cert_path, 'wb') as f:
                f.write(ca_cert.public_bytes(serialization.Encoding.PEM))
            os.chmod(self.ca_cert_path, 0o644)

            with open(self.server_cert_path, 'wb') as f:
                f.write(server_cert.public_bytes(serialization.Encoding.PEM))
            os.chmod(self.server_cert_path, 0o644)

            with open(self.server_key_path, 'wb') as f:
                f.write(server_key.private_bytes(
                    serialization.Encoding.PEM,
                    serialization.PrivateFormat.TraditionalOpenSSL,
                    serialization.NoEncryption(),
                ))
            os.chmod(self.server_key_path, 0o600)

            logger.info("Generated self-signed TLS certificates")

        except ImportError:
            logger.error(
                "cryptography package required for cert generation. "
                "Install with: pip install cryptography"
            )
            raise

    def load_server_credentials(self) -> grpc.ServerCredentials:
        """Load TLS credentials for the server."""
        if not self.certificates_exist():
            logger.info("Certificates not found, generating self-signed certs...")
            self.generate_self_signed_certs()

        with open(self.server_key_path, 'rb') as f:
            server_key = f.read()
        with open(self.server_cert_path, 'rb') as f:
            server_cert = f.read()
        with open(self.ca_cert_path, 'rb') as f:
            ca_cert = f.read()

        # Require client certificate for mutual TLS (mTLS)
        return grpc.ssl_server_credentials(
            [(server_key, server_cert)],
            root_certificates=ca_cert,
            require_client_auth=False,  # Set True for mTLS in production
        )


# --- Authentication Interceptor ---

class AuthenticationInterceptor(grpc.ServerInterceptor):
    """Server interceptor for API key authentication."""

    # Constant-time comparison to prevent timing attacks
    VALID_API_KEYS_HASHES: set = set()

    def __init__(self, api_keys: Optional[list] = None):
        """
        Initialize with a list of valid API keys.
        Keys are stored as SHA-256 hashes to avoid keeping plaintext in memory.
        """
        keys = api_keys or self._load_api_keys()
        for key in keys:
            key_hash = hashlib.sha256(key.encode()).hexdigest()
            self.VALID_API_KEYS_HASHES.add(key_hash)

        # Methods that don't require authentication
        self.public_methods = {'/dataprocessing.DataProcessor/HealthCheck'}

    @staticmethod
    def _load_api_keys() -> list:
        """Load API keys from environment or secure storage."""
        keys_str = os.environ.get('GRPC_API_KEYS', '')
        if keys_str:
            return [k.strip() for k in keys_str.split(',') if k.strip()]

        # Generate a default key for development
        default_key = secrets.token_urlsafe(32)
        logger.warning(
            f"No API keys configured. Generated development key: {default_key}"
        )
        return [default_key]

    def _validate_api_key(self, api_key: str) -> bool:
        """Validate API key using constant-time comparison."""
        if not api_key:
            return False
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        # Use hmac.compare_digest for constant-time comparison
        return any(
            hmac.compare_digest(key_hash, valid_hash)
            for valid_hash in self.VALID_API_KEYS_HASHES
        )

    def intercept_service(self, continuation, handler_call_details):
        """Intercept and authenticate incoming RPCs."""
        method = handler_call_details.method

        # Skip auth for public methods
        if method in self.public_methods:
            return continuation(handler_call_details)

        # Extract API key from metadata
        metadata = dict(handler_call_details.invocation_metadata or [])
        api_key = metadata.get('x-api-key', '')

        if not self._validate_api_key(api_key):
            logger.warning(
                f"Authentication failed for method {method} "
                f"from peer"
            )
            return self._unauthenticated_handler()

        return continuation(handler_call_details)

    @staticmethod
    def _unauthenticated_handler():
        """Return a handler that sends UNAUTHENTICATED status."""

        def _unary_unary(request, context):
            context.abort(
                grpc.StatusCode.UNAUTHENTICATED,
                'Invalid or missing API key'
            )

        def _unary_stream(request, context):
            context.abort(
                grpc.StatusCode.UNAUTHENTICATED,
                'Invalid or missing API key'
            )

        def _stream_unary(request_iterator, context):
            context.abort(
                grpc.StatusCode.UNAUTHENTICATED,
                'Invalid or missing API key'
            )

        def _stream_stream(request_iterator, context):
            context.abort(
                grpc.StatusCode.UNAUTHENTICATED,
                'Invalid or missing API key'
            )

        return grpc.unary_unary_rpc_method_handler(_unary_unary)


# --- Input Validation ---

class InputValidator:
    """Validates and sanitizes incoming request data."""

    # Maximum payload size: 64MB (configurable)
    MAX_PAYLOAD_SIZE = int(os.environ.get('MAX_PAYLOAD_SIZE', 64 * 1024 * 1024))
    MAX_METADATA_ENTRIES = 50
    MAX_METADATA_KEY_LENGTH = 256
    MAX_METADATA_VALUE_LENGTH = 4096
    MAX_REQUEST_ID_LENGTH = 256
    ALLOWED_DATA_TYPES = frozenset({
        'json', 'binary', 'text', 'protobuf', 'avro', 'parquet',
        'csv', 'msgpack', ''
    })

    @classmethod
    def validate_request(cls, request, context) -> bool:
        """Validate a DataRequest. Returns True if valid."""
        # Validate request_id
        if hasattr(request, 'request_id'):
            if len(request.request_id) > cls.MAX_REQUEST_ID_LENGTH:
                context.abort(
                    grpc.StatusCode.INVALID_ARGUMENT,
                    f'request_id exceeds maximum length of {cls.MAX_REQUEST_ID_LENGTH}'
                )
                return False

            # Sanitize: only allow alphanumeric, hyphens, underscores
            if request.request_id and not all(
                c.isalnum() or c in '-_.' for c in request.request_id
            ):
                context.abort(
                    grpc.StatusCode.INVALID_ARGUMENT,
                    'request_id contains invalid characters'
                )
                return False

        # Validate payload size
        if hasattr(request, 'payload') and len(request.payload) > cls.MAX_PAYLOAD_SIZE:
            context.abort(
                grpc.StatusCode.INVALID_ARGUMENT,
                f'Payload exceeds maximum size of {cls.MAX_PAYLOAD_SIZE} bytes'
            )
            return False

        # Validate data_type
        if hasattr(request, 'data_type'):
            if request.data_type.lower() not in cls.ALLOWED_DATA_TYPES:
                context.abort(
                    grpc.StatusCode.INVALID_ARGUMENT,
                    f'Unsupported data_type: {request.data_type}'
                )
                return False

        # Validate metadata
        if hasattr(request, 'metadata'):
            if len(request.metadata) > cls.MAX_METADATA_ENTRIES:
                context.abort(
                    grpc.StatusCode.INVALID_ARGUMENT,
                    f'Too many metadata entries (max {cls.MAX_METADATA_ENTRIES})'
                )
                return False

            for key, value in request.metadata.items():
                if len(key) > cls.MAX_METADATA_KEY_LENGTH:
                    context.abort(
                        grpc.StatusCode.INVALID_ARGUMENT,
                        f'Metadata key too long (max {cls.MAX_METADATA_KEY_LENGTH})'
                    )
                    return False
                if len(value) > cls.MAX_METADATA_VALUE_LENGTH:
                    context.abort(
                        grpc.StatusCode.INVALID_ARGUMENT,
                        f'Metadata value too long (max {cls.MAX_METADATA_VALUE_LENGTH})'
                    )
                    return False

        return True


# --- Metrics Collector ---

class MetricsCollector:
    """Thread-safe metrics collection for monitoring."""

    def __init__(self):
        self._lock = threading.Lock()
        self._requests_total = 0
        self._requests_by_method = {}
        self._errors_total = 0
        self._processing_times = deque(maxlen=10000)
        self._start_time = time.time()

    def record_request(self, method: str, processing_time_ns: int,
                       error: bool = False):
        with self._lock:
            self._requests_total += 1
            self._requests_by_method[method] = (
                self._requests_by_method.get(method, 0) + 1
            )
            self._processing_times.append(processing_time_ns)
            if error:
                self._errors_total += 1

    @property
    def requests_total(self) -> int:
        with self._lock:
            return self._requests_total

    @property
    def uptime_seconds(self) -> int:
        return int(time.time() - self._start_time)

    def get_stats(self) -> dict:
        with self._lock:
            times = list(self._processing_times)
            avg_time = sum(times) / len(times) if times else 0
            return {
                'requests_total': self._requests_total,
                'errors_total': self._errors_total,
                'avg_processing_time_ns': int(avg_time),
                'uptime_seconds': self.uptime_seconds,
                'requests_by_method': dict(self._requests_by_method),
            }


