    @staticmethod
    def _process_json(payload: bytes, metadata: dict) -> bytes:
        """Process JSON data."""
        import json
        try:
            data = json.loads(payload)
            # Add processing metadata
            if isinstance(data, dict):
                data['_processed'] = True
                data['_timestamp'] = time.time_ns()
            return json.dumps(data).encode()
        except (json.JSONDecodeError, UnicodeDecodeError):
            return payload

    @staticmethod
    def _process_binary(payload: bytes, metadata: dict) -> bytes:
        """Process binary data."""
        # Compute checksum as example processing
        checksum = hashlib.sha256(payload).digest()
        return checksum + payload

    @staticmethod
    def _process_generic(payload: bytes, metadata: dict) -> bytes:
        """Generic data processing."""
        return payload


