metrics = MetricsCollector()


class DataProcessorServicer:
    """
    Implementation of the DataProcessor gRPC service.
    Handles unary, server-streaming, client-streaming, and
    bidirectional streaming RPCs.
    """

    def __init__(self):
        self.engine = DataProcessingEngine()
        self.metrics = metrics

    def _create_response(self, request_id: str, result: bytes,
                         status: str, metadata: dict,
                         processing_time_ns: int):
        """Create a DataResponse."""
        if pb2 is not None:
            resp = pb2.DataResponse(
                request_id=request_id,
                result=result,
                status=status,
                processing_time_ns=processing_time_ns,
            )
            for k, v in metadata.items():
                resp.metadata[k] = v
            return resp
        else:
            return ManualDataResponse(
                request_id=request_id,
                result=result,
                status=status,
                metadata=metadata,
                processing_time_ns=processing_time_ns,
            )

    def _create_health_response(self, status: str, uptime: int,
                                requests: int):
        """Create a HealthResponse."""
        if pb2 is not None:
            return pb2.HealthResponse(
                status=status,
                uptime_seconds=uptime,
                requests_processed=requests,
            )
        else:
            return ManualHealthResponse(
                status=status,
                uptime_seconds=uptime,
                requests_processed=requests,
            )

    def ProcessData(self, request, context):
        """Unary RPC: Process a single data request."""
        start = time.time_ns()

        if not InputValidator.validate_request(request, context):
            return self._create_response(
                getattr(request, 'request_id', ''),
                b'', 'INVALID', {}, 0
            )

        try:
            result = self.engine.process(
                request.payload,
                request.data_type,
                dict(request.metadata) if hasattr(request, 'metadata') else {},
            )

            processing_time = time.time_ns() - start
            self.metrics.record_request('ProcessData', processing_time)

            return self._create_response(
                request.request_id,
                result,
                'SUCCESS',
                {'processor': 'unary'},
                processing_time,
            )

        except Exception as e:
            processing_time = time.time_ns() - start
            self.metrics.record_request('ProcessData', processing_time, error=True)
            logger.error(f"Error processing request {request.request_id}: {e}")
            context.abort(
                grpc.StatusCode.INTERNAL,
                'Internal processing error'
            )

    def StreamResults(self, request, context):
        """Server streaming RPC: Process request and stream results."""
        start = time.time_ns()

        if not InputValidator.validate_request(request, context):
            return

        try:
            result = self.engine.process(
                request.payload,
                request.data_type,
                dict(request.metadata) if hasattr(request, 'metadata') else {},
            )

            # Stream results in chunks for large payloads
            chunk_size = 32 * 1024  # 32KB chunks
            total_chunks = (len(result) + chunk_size - 1) // chunk_size
            total_chunks = max(total_chunks, 1)

            for i in range(total_chunks):
                if context.is_active():
                    chunk = result[i * chunk_size:(i + 1) * chunk_size]
                    processing_time = time.time_ns() - start

                    yield self._create_response(
                        request.request_id,
                        chunk,
                        'STREAMING',
                        {
                            'chunk_index': str(i),
                            'total_chunks': str(total_chunks),
                        },
                        processing_time,
                    )
                else:
                    logger.info(
                        f"Client disconnected during stream "
                        f"for request {request.request_id}"
                    )
                    break

            processing_time = time.time_ns() - start
            self.metrics.record_request('StreamResults', processing_time)

        except Exception as e:
            processing_time = time.time_ns() - start
            self.metrics.record_request('StreamResults', processing_time, error=True)
            logger.error(f"Error in StreamResults: {e}")
            context.abort(
                grpc.StatusCode.INTERNAL,
                'Internal streaming error'
            )

    def IngestStream(self, request_iterator, context):
        """Client streaming RPC: Ingest a stream of data."""
        start = time.time_ns()
        total_bytes = 0
        message_count = 0
        accumulated_results = []

        try:
            for request in request_iterator:
                if not context.is_active():
                    break

                if not InputValidator.validate_request(request, context):
                    continue

                result = self.engine.process(
                    request.payload,
                    request.data_type,
                    dict(request.metadata) if hasattr(request, 'metadata') else {},
                )

                accumulated_results.append(result)
                total_bytes += len(request.payload)
                message_count += 1

            processing_time = time.time_ns() - start
            self.metrics.record_request('IngestStream', processing_time)

            # Combine results
            combined = b''.join(accumulated_results)

            return self._create_response(
                f'batch-{message_count}',
                combined[:1024 * 1024],  # Cap response at 1MB
                'SUCCESS',
                {
                    'messages_processed': str(message_count),
                    'total_bytes_ingested': str(total_bytes),
                },
                processing_time,
            )

        except Exception as e:
            processing_time = time.time_ns() - start
            self.metrics.record_request('IngestStream', processing_time, error=True)
            logger.error(f"Error in IngestStream: {e}")
            context.abort(
                grpc.StatusCode.INTERNAL,
                'Internal ingestion error'
            )

    def ProcessStream(self, request_iterator, context):
        """
        Bidirectional streaming RPC: Real-time processing pipeline.
        Processes each incoming message and immediately streams back results.
        """
        message_count = 0

        try:
            for request in request_iterator:
                if not context.is_active():
                    break

                start = time.time_ns()

                if not InputValidator.validate_request(request, context):
                    # Send error response but continue processing
                    yield self._create_response(
                        getattr(request, 'request_id', ''),
                        b'',
                        'VALIDATION_ERROR',
                        {},
                        time.time_ns() - start,
                    )
                    continue

                result = self.engine.process(
                    request.payload,
                    request.data_type,
                    dict(request.metadata) if hasattr(request, 'metadata') else {},
                )

                processing_time = time.time_ns() - start
                message_count += 1
                self.metrics.record_request('ProcessStream', processing_time)

                yield self._create_response(
                    request.request_id,
                    result,
                    'SUCCESS',
                    {
                        'sequence': str(message_count),
                        'processor': 'bidirectional',
                    },
                    processing_time,
                )

        except Exception as e:
            self.metrics.record_request('ProcessStream', 0, error=True)
            logger.error(f"Error in ProcessStream after {message_count} messages: {e}")
            context.abort(
                grpc.StatusCode.INTERNAL,
                'Internal stream processing error'
            )

    def HealthCheck(self, request, context):
        """Health check endpoint."""
        stats = self.metrics.get_stats()
        return self._create_health_response(
            'SERVING',
            stats['uptime_seconds'],
            stats['requests_total'],
        )


