class GRPCServerConfig:
    """Server configuration with secure defaults."""

    def __init__(self):
        # Server address - bind to localhost by default for security
        self.host = os.environ.get('GRPC_HOST', '127.0.0.1')
        self.port = int(os.environ.get('GRPC_PORT', '50051'))

        # Thread pool configuration
        self.max_workers = int(os.environ.get(
            'GRPC_MAX_WORKERS',
            str(min(32, (os.cpu_count() or 4) * 4))
        ))

        # Channel options for performance
        self.channel_options = [
            # Enable keepalive
            ('grpc.keepalive_time_ms', 30000),
            ('grpc.keepalive_timeout_ms', 10000),
            ('grpc.keepalive_permit_without_calls', 1),
            ('grpc.http2.min_ping_interval_without_data_ms', 30000),

            # Max message sizes (64MB)
            ('grpc.max_send_message_length', 64 * 1024 * 1024),
            ('grpc.max_receive_message_length', 64 * 1024 * 1024),

            # Connection management
            ('grpc.max_connection_idle_ms', 300000),
            ('grpc.max_connection_age_ms', 600000),
            ('grpc.max_connection_age_grace_ms', 30000),

            # HTTP/2 settings for throughput
            ('grpc.http2.max_pings_without_data', 0),
            ('grpc.http2.min_time_between_pings_ms', 10000),

            # Enable SO_REUSEPORT for better load distribution
            ('grpc.so_reuseport', 1),
        ]

        # TLS configuration
        self.use_tls = os.environ.get('GRPC_USE_TLS', 'true').lower() == 'true'
        self.cert_dir = os.environ.get('GRPC_CERT_DIR', None)

        # Authentication
        self.require_auth = os.environ.get(
            'GRPC_REQUIRE_AUTH', 'true'
        ).lower() == 'true'
        self.api_keys = None
        api_keys_env = os.environ.get('GRPC_API_KEYS', '')
        if api_keys_env:
            self.api_keys = [k.strip() for k in api_keys_env.split(',') if k.strip()]


def create_server(config: Optional[GRPCServerConfig] = None) -> grpc.Server:
    """Create and configure the gRPC server."""
    config = config or GRPCServerConfig()

    # Build interceptors
    interceptors = []
    if config.require_auth:
        interceptors.append(AuthenticationInterceptor(config.api_keys))

    # Create thread pool
    thread_pool = futures.ThreadPoolExecutor(
        max_workers=config.max_workers,
        thread_name_prefix='grpc-worker',
    )

    # Create server
    server = grpc.server(
        thread_pool,
        interceptors=interceptors,
        options=config.channel_options,
        maximum_concurrent_rpcs=config.max_workers * 4,
    )

    # Register service
    servicer = DataProcessorServicer()

    if pb2_grpc is not None:
        # Use generated service registration
        pb2_grpc.add_DataProcessorServicer_to_server(servicer, server)
    else:
        # Manual service registration using generic handlers
        from grpc import unary_unary_rpc_method_handler
        from grpc import unary_stream_rpc_method_handler
        from grpc import stream_unary_rpc_method_handler
        from grpc import stream_stream_rpc_method_handler

        method_handlers = {
            'ProcessData': unary_unary_rpc_method_handler(
                servicer.ProcessData,
            ),
            'StreamResults': unary_stream_rpc_method_handler(
                servicer.StreamResults,
            ),
            'IngestStream': stream_unary_rpc_method_handler(
                servicer.IngestStream,
            ),
            'ProcessStream': stream_stream_rpc_method_handler(
                servicer.ProcessStream,
            ),
            'HealthCheck': unary_unary_rpc_method_handler(
                servicer.HealthCheck,
            ),
        }

        generic_handler = grpc.method_service_handler(
            'dataprocessing.DataProcessor',
            method_handlers,
        ) if hasattr(grpc, 'method_service_handler') else None

        if generic_handler:
            server.add_generic_rpc_handlers([generic_handler])
        else:
            logger.warning(
                "Could not register generic handlers. "
                "Proto generation recommended."
            )

    # Configure port with TLS
    address = f'{config.host}:{config.port}'

    if config.use_tls:
        try:
            tls_manager = TLSCertificateManager(config.cert_dir)
            credentials = tls_manager.load_server_credentials()
            server.add_secure_port(address, credentials)
            logger.info(f"Server configured with TLS on {address}")
        except Exception as e:
            logger.error(f"Failed to configure TLS: {e}")
            logger.warning("Falling back to insecure port (NOT for production)")
            server.add_insecure_port(address)
    else:
        logger.warning(
            "TLS disabled. This is NOT recommended for production."
        )
        server.add_insecure_port(address)

    return server


def serve():
    """Start the gRPC server with graceful shutdown."""
    config = GRPCServerConfig()
    server = create_server(config)

    # Graceful shutdown handling
    shutdown_event = threading.Event()

    def signal_handler(signum, frame):
        logger.info(f"Received signal {signum}, initiating graceful shutdown...")
        shutdown_event.set()

    signal.signal(signal.SIGTERM, signal_handler)
    signal.signal(signal.SIGINT, signal_handler)

    # Start server
    server.start()
    logger.info(
        f"gRPC DataProcessor server started on "
        f"{config.host}:{config.port} "
        f"(workers={config.max_workers}, "
        f"tls={'enabled' if config.use_tls else 'disabled'}, "
        f"auth={'enabled' if config.require_auth else 'disabled'})"
    )

    # Periodic stats logging
    def log_stats():
        while not shutdown_event.is_set():
            shutdown_event.wait(60)
            if not shutdown_event.is_set():
                stats = metrics.get_stats()
                logger.info(f"Server stats: {stats}")

    stats_thread = threading.Thread(target=log_stats, daemon=True)
    stats_thread.start()

    # Wait for shutdown signal
    try:
        shutdown_event.wait()
    except KeyboardInterrupt:
        pass

    # Graceful shutdown with timeout
    logger.info("Shutting down server (30s grace period)...")
    shutdown_complete = server.stop(grace=30)
    shutdown_complete.wait()
    logger.info("Server shutdown complete.")


# --- Client Example (for testing) ---

def create_test_client(host='127.0.0.1', port=50051, use_tls=True,
                       api_key=None, cert_dir=None):
    """Create a test client for the server."""
    address = f'{host}:{port}'

    if use_tls:
        tls_manager = TLSCertificateManager(cert_dir)
        with open(tls_manager.ca_cert_path, 'rb') as f:
            ca_cert = f.read()
        credentials = grpc.ssl_channel_credentials(
            root_certificates=ca_cert,
        )
        channel = grpc.secure_channel(address, credentials)
    else:
        channel = grpc.insecure_channel(address)

    return channel


if __name__ == '__main__':
    serve()